/**
 * resolveCliVersion — returns the CLI version for `ant --version` per m6.1
 * Q3 brew-test contract.
 *
 * Two-tier strategy:
 *   1. PRIMARY: import the auto-generated ANT_CLI_VERSION_CONSTANT from
 *      `./ant-cli-version-constant.mjs`. The constant is regenerated by
 *      `node scripts/build-cli-version-constant.mjs` BEFORE every
 *      `bun build --compile`, so the single-binary release retains the
 *      version. Bun bundles the constant module into the compiled binary.
 *   2. FALLBACK: if the constant is somehow missing or empty (dev mode
 *      with a stale generated file), read package.json directly. Both
 *      paths return '0.0.0-unknown' as a last resort.
 *
 * Defensive — never throws into the caller.
 */
import { readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { ANT_CLI_VERSION_CONSTANT } from './ant-cli-version-constant.mjs';

export function resolveCliVersion() {
  if (typeof ANT_CLI_VERSION_CONSTANT === 'string' && ANT_CLI_VERSION_CONSTANT.length > 0) {
    return ANT_CLI_VERSION_CONSTANT;
  }
  try {
    const here = dirname(fileURLToPath(import.meta.url));
    const pkgPath = join(here, '..', 'package.json');
    const raw = readFileSync(pkgPath, 'utf8');
    const pkg = JSON.parse(raw);
    return typeof pkg.version === 'string' ? pkg.version : '0.0.0-unknown';
  } catch {
    return '0.0.0-unknown';
  }
}
